<!DOCTYPE html><html lang="ru"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Каналы Telegram — SkyGuardian</title><style>*{box-sizing:border-box}body{margin:0;background:#08101d;color:#e8eef8;font-family:Inter,system-ui,sans-serif}.wrap{max-width:1100px;margin:auto;padding:24px}.top{display:flex;justify-content:space-between;align-items:center;gap:14px;margin-bottom:22px}.back,.btn{display:inline-flex;align-items:center;justify-content:center;padding:10px 14px;border:1px solid #2a3952;border-radius:9px;background:#111d30;color:#dce6f4;text-decoration:none;cursor:pointer}.btn.primary{background:#1769ff;border-color:#1769ff;color:#fff}.btn.success{border-color:#256a50;color:#72e1ad}.title h1{margin:0 0 6px;font-size:26px}.title p{margin:0;color:#8190a6}.flash,.errors{padding:13px 15px;border-radius:10px;margin-bottom:16px}.flash{background:#10291f;border:1px solid #225d46;color:#7ee0ad}.errors{background:#2b151a;border:1px solid #66323b;color:#ff9aaa}.search{width:100%;padding:13px 14px;margin-bottom:16px;border:1px solid #2a3952;border-radius:10px;background:#0c1626;color:#fff}.list{border:1px solid #21304a;border-radius:14px;background:#0f192a;overflow:hidden}.row{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:16px;align-items:center;padding:16px;border-top:1px solid #1b293d}.row:first-child{border-top:0}.name{font-weight:750}.meta{margin-top:5px;color:#78869b;font-size:12px}.actions{display:flex;gap:8px;flex-wrap:wrap}.empty{padding:30px;text-align:center;color:#75849a}@media(max-width:650px){.wrap{padding:16px}.top{align-items:flex-start;flex-direction:column}.row{grid-template-columns:1fr}.actions{display:grid;grid-template-columns:1fr}.btn{width:100%}.title h1{font-size:23px}}</style></head><body><main class="wrap"><div class="top"><div class="title"><h1>Каналы аккаунта «{{ $telegramAccount->name }}»</h1><p>Выберите канал или откройте последние 10 сообщений.</p></div><a class="back" href="{{ route('integrations.index') }}">← Интеграции</a></div>@if(session('status'))<div class="flash">{{ session('status') }}</div>@endif @if($errors->any())<div class="errors">{{ $errors->first() }}</div>@endif<input class="search" id="search" placeholder="Поиск канала..." oninput="filterRows()"><section class="list" id="list">@forelse($dialogs as $dialog)<div class="row" data-name="{{ mb_strtolower($dialog['name'].' '.($dialog['username'] ?? '')) }}"><div><div class="name">{{ $dialog['name'] }}</div><div class="meta">{{ $dialog['username'] ? '@'.$dialog['username'].' · ' : '' }}{{ $dialog['peer_id'] }}</div></div><div class="actions">@if(in_array($dialog['peer_id'],$selectedPeerIds,true))<span class="btn success">Добавлен</span>@else<form method="POST" action="{{ route('integrations.telegram.dialogs.store',$telegramAccount) }}">@csrf<input type="hidden" name="peer_id" value="{{ $dialog['peer_id'] }}"><input type="hidden" name="name" value="{{ $dialog['name'] }}"><input type="hidden" name="username" value="{{ $dialog['username'] }}"><button class="btn success" type="submit">Добавить в источники</button></form>@endif<a class="btn primary" href="{{ route('integrations.telegram.messages',['telegramAccount'=>$telegramAccount,'peer_id'=>$dialog['peer_id'],'name'=>$dialog['name']]) }}">Сообщения</a></div></div>@empty<div class="empty">Каналы и супергруппы не найдены.</div>@endforelse</section></main><script>function filterRows(){const q=document.getElementById('search').value.toLowerCase();document.querySelectorAll('.row').forEach(r=>r.style.display=r.dataset.name.includes(q)?'grid':'none')}</script></body></html>